1	// NOAA solar position algorithm — TypeScript port for 60-fps viewport updates.
2	// Deterministic, no dependencies. Matches the Python implementation in
3	// app/bim_ai/site/sun_position.py.
4	
5	export function computeSunPositionNoaa(
6	  latDeg: number,
7	  lonDeg: number,
8	  dateIso: string,
9	  hours: number,
10	  minutes: number,
11	  dstStrategy: 'auto' | 'on' | 'off' = 'auto',
12	  utcOffsetHours?: number,
13	): { azimuthDeg: number; elevationDeg: number } {
14	  const [year, month, day] = dateIso.split('-').map(Number);
15	
16	  if (utcOffsetHours === undefined) {
17	    utcOffsetHours = Math.round(lonDeg / 15);
18	  }
19	
20	  let dstHours = 0;
21	  if (dstStrategy === 'on') {
22	    dstHours = 1;
23	  } else if (dstStrategy === 'auto') {
24	    if (latDeg >= 0 && month >= 3 && month <= 10) dstHours = 1;
25	    else if (latDeg < 0 && (month >= 9 || month <= 4)) dstHours = 1;
26	  }
27	
28	  const localHours = hours + minutes / 60;
29	  const utHours = (((localHours - utcOffsetHours - dstHours) % 24) + 24) % 24;
30	
31	  const jd = julianDay(year, month, day, utHours);
32	  const T = (jd - 2451545.0) / 36525.0;
33	
34	  const L0 = (((280.46646 + T * (36000.76983 + T * 0.0003032)) % 360) + 360) % 360;
35	  const M = 357.52911 + T * (35999.05029 - 0.0001537 * T);
36	  const e = 0.016708634 - T * (0.000042037 + 0.0000001267 * T);
37	
38	  const Mrad = toRad(M);
39	  const C =
40	    (1.914602 - T * (0.004817 + 0.000014 * T)) * Math.sin(Mrad) +
41	    (0.019993 - 0.000101 * T) * Math.sin(2 * Mrad) +
42	    0.000289 * Math.sin(3 * Mrad);
43	
44	  const sunLon = L0 + C;
45	  const omega = 125.04 - 1934.136 * T;
46	  const apparentLon = sunLon - 0.00569 - 0.00478 * Math.sin(toRad(omega));
47	
48	  const meanObliq = 23 + (26 + (21.448 - T * (46.815 + T * (0.00059 - T * 0.001813))) / 60) / 60;
49	  const obliqCorr = meanObliq + 0.00256 * Math.cos(toRad(omega));
50	
51	  const declination = toDeg(Math.asin(Math.sin(toRad(obliqCorr)) * Math.sin(toRad(apparentLon))));
52	
53	  const y = Math.tan(toRad(obliqCorr / 2)) ** 2;
54	  const L0rad = toRad(L0);
55	  const Mrad2 = toRad(M);
56	  const eot =
57	    4 *
58	    toDeg(
59	      y * Math.sin(2 * L0rad) -
60	        2 * e * Math.sin(Mrad2) +
61	        4 * e * y * Math.sin(Mrad2) * Math.cos(2 * L0rad) -
62	        0.5 * y * y * Math.sin(4 * L0rad) -
63	        1.25 * e * e * Math.sin(2 * Mrad2),
64	    );
65	
66	  const trueSolarTime = (((utHours * 60 + eot + 4 * lonDeg) % 1440) + 1440) % 1440;
67	  const hourAngle = trueSolarTime / 4 < 0 ? trueSolarTime / 4 + 180 : trueSolarTime / 4 - 180;
68	
69	  const latRad = toRad(latDeg);
70	  const declRad = toRad(declination);
71	  const haRad = toRad(hourAngle);
72	
73	  const cosZenith = Math.max(
74	    -1,
75	    Math.min(
76	      1,
77	      Math.sin(latRad) * Math.sin(declRad) + Math.cos(latRad) * Math.cos(declRad) * Math.cos(haRad),
78	    ),
79	  );
80	  const zenith = toDeg(Math.acos(cosZenith));
81	  const elevation = 90 - zenith;
82	
83	  let refraction = 0;
84	  if (elevation > 85) {
85	    refraction = 0;
86	  } else if (elevation > 5) {
87	    const tanEl = Math.tan(toRad(elevation));
88	    refraction = (58.1 / tanEl - 0.07 / tanEl ** 3 + 0.000086 / tanEl ** 5) / 3600;
89	  } else if (elevation > -0.575) {
90	    refraction =
91	      (1735 +
92	        elevation * (-518.2 + elevation * (103.4 + elevation * (-12.79 + elevation * 0.711)))) /
93	      3600;
94	  } else {
95	    refraction = -20.772 / Math.tan(toRad(elevation)) / 3600;
96	  }
97	
98	  const elevationCorrected = elevation + refraction;
99	
100	  const cosAzNum = Math.sin(latRad) * Math.cos(toRad(zenith)) - Math.sin(declRad);
101	  const cosAzDen = Math.cos(latRad) * Math.sin(toRad(zenith));
102	
103	  let azimuth = 0;
104	  if (Math.abs(cosAzDen) >= 1e-10) {
105	    const cosAz = Math.max(-1, Math.min(1, cosAzNum / cosAzDen));
106	    const azimuthRaw = toDeg(Math.acos(cosAz));
107	    azimuth = hourAngle > 0 ? (azimuthRaw + 180) % 360 : (540 - azimuthRaw) % 360;
108	  }
109	
110	  return { azimuthDeg: azimuth, elevationDeg: elevationCorrected };
111	}
112	
113	function julianDay(year: number, month: number, day: number, utHours: number): number {
114	  let y = year;
115	  let m = month;
116	  if (m <= 2) {
117	    y -= 1;
118	    m += 12;
119	  }
120	  const A = Math.floor(y / 100);
121	  const B = 2 - A + Math.floor(A / 4);
122	  return (
123	    Math.floor(365.25 * (y + 4716)) +
124	    Math.floor(30.6001 * (m + 1)) +
125	    day +
126	    utHours / 24 +
127	    B -
128	    1524.5
129	  );
130	}
131	
132	function toRad(deg: number): number {
133	  return deg * (Math.PI / 180);
134	}
135	
136	function toDeg(rad: number): number {
137	  return rad * (180 / Math.PI);
138	}
