            ]
          : [action('element-sidebar-toggle', 'Element Actions', 'select', '3d-element-actions')],
      },
      ...(isSolid || isWall
        ? [
            {
              id: 'constraints',
              label: 'Constraints',
              commands: [
                ...(isSolid ? [tool('unjoin', 'Unjoin', 'unjoin')] : []),
                ...(isWall ? [tool('attach', 'Attach Top', 'attach')] : []),
                ...(isWall ? [tool('detach', 'Detach Top', 'detach')] : []),
