interface SunOverlayProps {
  values: SunOverlayValues;
  azimuthDeg: number;
  elevationDeg: number;
  onChange: (patch: Partial<SunOverlayValues>) => void;
  onCommit: (patch: Partial<SunOverlayValues>) => void;
