        position: 'absolute',
        top: 'var(--space-3)',
        right: 'var(--space-3)',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'flex-end',
        gap: 'var(--space-1)',
        zIndex: 10,
        pointerEvents: 'none',
      }}
